create extension if not exists pgcrypto;
create table public.profiles(id uuid primary key references auth.users(id) on delete cascade,role varchar(30) not null default 'user' check(role in('admin','user')),created_at timestamptz not null default now());
create table public.categories(id uuid primary key default gen_random_uuid(),name varchar(120) not null,slug varchar(140) not null unique,description text,image_url text,icon varchar(16) not null default '🍬',is_active boolean not null default true,sort_order integer not null default 0,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.products(id uuid primary key default gen_random_uuid(),category_id uuid references public.categories(id) on delete set null,name varchar(160) not null,slug varchar(180) not null unique,description text,sku varchar(80) unique,price numeric(12,2) not null check(price>=0),offer_price numeric(12,2) check(offer_price>=0 and offer_price<price),offer_starts_at timestamptz,offer_ends_at timestamptz,stock integer check(stock is null or stock>=0),track_stock boolean not null default false,image_url text,is_active boolean not null default true,is_featured boolean not null default false,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),check(offer_ends_at is null or offer_starts_at is null or offer_ends_at>offer_starts_at));
create table public.product_images(id uuid primary key default gen_random_uuid(),product_id uuid not null references public.products(id) on delete cascade,image_url text not null,alt_text varchar(200),sort_order integer not null default 0,is_primary boolean not null default false,created_at timestamptz not null default now());
create table public.banners(id uuid primary key default gen_random_uuid(),title varchar(180) not null,subtitle text,image_url text not null,button_text varchar(80),button_url text,starts_at timestamptz,ends_at timestamptz,is_active boolean not null default true,sort_order integer not null default 0,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),check(ends_at is null or starts_at is null or ends_at>starts_at));
create table public.orders(id uuid primary key default gen_random_uuid(),order_number varchar(40) not null unique,idempotency_key uuid not null unique,customer_name varchar(160) not null,customer_phone varchar(30) not null,customer_email varchar(180),customer_address text not null,delivery_method varchar(40) not null check(delivery_method='local_delivery'),notes text,subtotal numeric(12,2) not null check(subtotal>=0),total numeric(12,2) not null check(total>=0),status varchar(40) not null default 'new' check(status in('new','contacted','confirmed','preparing','ready','completed','cancelled')),created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.order_items(id uuid primary key default gen_random_uuid(),order_id uuid not null references public.orders(id) on delete cascade,product_id uuid references public.products(id) on delete set null,product_name varchar(160) not null,sku varchar(80),unit_price numeric(12,2) not null check(unit_price>=0),quantity integer not null check(quantity>0),subtotal numeric(12,2) not null check(subtotal>=0),created_at timestamptz not null default now());
create index products_category_idx on public.products(category_id);create index order_items_order_idx on public.order_items(order_id);create index orders_created_idx on public.orders(created_at desc);
create or replace function public.is_admin() returns boolean language sql stable security definer set search_path='' as $$select exists(select 1 from public.profiles where id=auth.uid() and role='admin')$$;
alter table public.profiles enable row level security;alter table public.categories enable row level security;alter table public.products enable row level security;alter table public.product_images enable row level security;alter table public.banners enable row level security;alter table public.orders enable row level security;alter table public.order_items enable row level security;
create policy "public active categories" on public.categories for select using(is_active or public.is_admin());
create policy "public active products" on public.products for select using(is_active or public.is_admin());
create policy "public images active products" on public.product_images for select using(exists(select 1 from public.products p where p.id=product_id and p.is_active) or public.is_admin());
create policy "public current banners" on public.banners for select using((is_active and(starts_at is null or starts_at<=now())and(ends_at is null or ends_at>=now()))or public.is_admin());
create policy "admin profiles" on public.profiles for select using(id=auth.uid() or public.is_admin());
create policy "admin categories all" on public.categories for all using(public.is_admin()) with check(public.is_admin());create policy "admin products all" on public.products for all using(public.is_admin()) with check(public.is_admin());create policy "admin images all" on public.product_images for all using(public.is_admin()) with check(public.is_admin());create policy "admin banners all" on public.banners for all using(public.is_admin()) with check(public.is_admin());create policy "admin orders all" on public.orders for all using(public.is_admin()) with check(public.is_admin());create policy "admin order items" on public.order_items for select using(public.is_admin());
create sequence public.order_daily_seq;
create or replace function public.create_store_order(payload jsonb) returns jsonb language plpgsql security definer set search_path='public' as $$declare v_order_id uuid;v_order_number text;v_total numeric(12,2):=0;v_item jsonb;v_product products%rowtype;v_quantity integer;v_price numeric(12,2);v_existing orders%rowtype;begin
select * into v_existing from orders where idempotency_key=(payload->>'idempotency_key')::uuid;if found then return jsonb_build_object('order_number',v_existing.order_number,'total',v_existing.total);end if;
if jsonb_array_length(payload->'items')=0 then raise exception 'empty cart';end if;
for v_item in select * from jsonb_array_elements(payload->'items') loop v_quantity:=(v_item->>'quantity')::integer;if v_quantity<1 or v_quantity>99 then raise exception 'invalid quantity';end if;select * into v_product from products where id=(v_item->>'product_id')::uuid and is_active for update;if not found then raise exception 'product unavailable';end if;if v_product.track_stock and coalesce(v_product.stock,0)<v_quantity then raise exception 'insufficient stock';end if;v_price:=case when v_product.offer_price is not null and(v_product.offer_starts_at is null or v_product.offer_starts_at<=now())and(v_product.offer_ends_at is null or v_product.offer_ends_at>=now())then v_product.offer_price else v_product.price end;v_total:=v_total+v_price*v_quantity;end loop;
v_order_number:='CAR-'||to_char(now() at time zone 'America/Mexico_City','YYYYMMDD')||'-'||lpad(nextval('order_daily_seq')::text,4,'0');insert into orders(order_number,idempotency_key,customer_name,customer_phone,customer_email,customer_address,delivery_method,notes,subtotal,total)values(v_order_number,(payload->>'idempotency_key')::uuid,payload->>'customer_name',payload->>'customer_phone',nullif(payload->>'customer_email',''),nullif(payload->>'customer_address',''),payload->>'delivery_method',nullif(payload->>'notes',''),v_total,v_total)returning id into v_order_id;
for v_item in select * from jsonb_array_elements(payload->'items') loop v_quantity:=(v_item->>'quantity')::integer;select * into v_product from products where id=(v_item->>'product_id')::uuid for update;v_price:=case when v_product.offer_price is not null and(v_product.offer_starts_at is null or v_product.offer_starts_at<=now())and(v_product.offer_ends_at is null or v_product.offer_ends_at>=now())then v_product.offer_price else v_product.price end;insert into order_items(order_id,product_id,product_name,sku,unit_price,quantity,subtotal)values(v_order_id,v_product.id,v_product.name,v_product.sku,v_price,v_quantity,v_price*v_quantity);if v_product.track_stock then update products set stock=stock-v_quantity where id=v_product.id;end if;end loop;return jsonb_build_object('order_number',v_order_number,'total',v_total);exception when unique_violation then select * into v_existing from orders where idempotency_key=(payload->>'idempotency_key')::uuid;return jsonb_build_object('order_number',v_existing.order_number,'total',v_existing.total);end$$;
revoke all on function public.create_store_order(jsonb) from public,anon,authenticated;
insert into storage.buckets(id,name,public,file_size_limit,allowed_mime_types) values('products','products',true,3145728,array['image/jpeg','image/png','image/webp']),('categories','categories',true,3145728,array['image/jpeg','image/png','image/webp']),('banners','banners',true,3145728,array['image/jpeg','image/png','image/webp']),('branding','branding',true,3145728,array['image/jpeg','image/png','image/webp']) on conflict(id) do nothing;
create policy "public storage read" on storage.objects for select using(bucket_id in('products','categories','banners','branding'));create policy "admin storage insert" on storage.objects for insert to authenticated with check(bucket_id in('products','categories','banners','branding')and public.is_admin());create policy "admin storage update" on storage.objects for update to authenticated using(public.is_admin()) with check(public.is_admin());create policy "admin storage delete" on storage.objects for delete to authenticated using(public.is_admin());
